Javascript.validate:
var val = Services.getValue(PaidOnAccountAmt.dataBinding);
//var err = WPU.validateCurrency(val);
var err = validateCurrencyValue(val, 999999.99);
if( null == err )
{	var fVal = WPU.formatToTwoDP(val);
	Services.setValue(PaidOnAccountAmt.dataBinding, fVal);
}
return err;

