function DefaultCurrency339() {}
DefaultCurrency339.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency339.tabIndex = -1;
DefaultCurrency339.maxLength = 3;
DefaultCurrency339.isReadOnly = function(){return true;}
DefaultCurrency339.isTemporary = function(){return true;}
DefaultCurrency339.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency339.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
